description:
Implement the Gemini CLI executor:

```go
// executor.go
package main

import (
    "context"
    "fmt"
    "os"
    "os/exec"
    "path/filepath"
    "strings"
    "time"
)

type Executor struct {
    Model        string
    OutputFormat string // "text", "json", "stream-json"
    Timeout      time.Duration
    Verbose      bool
}

func (e *Executor) Execute(prompt string) (string, error) {
    ctx, cancel := context.WithTimeout(context.Background(), e.Timeout)
    defer cancel()

    // Build args
    args := []string{"-m", e.Model, "--yolo", "-e", "none"}
    if e.OutputFormat != "" {
        args = append(args, "-o", e.OutputFormat)
    }

    if e.Verbose {
        fmt.Fprintf(os.Stderr, "DEBUG: gemini %s\n", strings.Join(args, " "))
        fmt.Fprintf(os.Stderr, "DEBUG: prompt length: %d bytes\n", len(prompt))
    }

    cmd := exec.CommandContext(ctx, "gemini", args...)
    cmd.Stdin = strings.NewReader(prompt)

    // Override HOME for gemini-slave config
    home, _ := os.UserHomeDir()
    slaveHome := filepath.Join(home, ".gemini-slave")
    cmd.Env = make([]string, 0, len(os.Environ())+1)
    for _, e := range os.Environ() {
        if !strings.HasPrefix(e, "HOME=") {
            cmd.Env = append(cmd.Env, e)
        }
    }
    cmd.Env = append(cmd.Env, "HOME="+slaveHome)

    output, err := cmd.Output()

    if ctx.Err() == context.DeadlineExceeded {
        return "", fmt.Errorf("gemini execution timed out after %v", e.Timeout)
    }

    if err != nil {
        if exitErr, ok := err.(*exec.ExitError); ok {
            return "", fmt.Errorf("gemini failed (exit %d): %s", 
                exitErr.ExitCode(), string(exitErr.Stderr))
        }
        return "", fmt.Errorf("gemini execution failed: %w", err)
    }

    return string(output), nil
}
```

Key requirements:
- context.WithTimeout for reliable timeout
- HOME override to ~/.gemini-slave
- Capture stderr on failure
- Verbose mode for debugging
